$esc = [char]27
$url = 'https://en.wikipedia.org/wiki/Lenna'
$label = $url
$viewWidth = try { [Console]::WindowWidth } catch { 80 }
if ($viewWidth -le 0) { $viewWidth = 80 }
$leftPad = [Math]::Max(0, [int][Math]::Floor(($viewWidth - $label.Length) / 2))
$pad = ' ' * $leftPad
[Console]::WriteLine()
[Console]::Write("${pad}${esc}]8;;${url}${esc}\${label}${esc}]8;;${esc}\")
[Console]::WriteLine()
[string[]]$footerLines = @(
    '...only true devs knows...',
    '...simpler times man...'
)

foreach ($footerLine in $footerLines) {
    $footerPad = [Math]::Max(0, [int][Math]::Floor(($viewWidth - $footerLine.Length) / 2))
    $footerPadText = ' ' * $footerPad

    [Console]::WriteLine("${footerPadText}${footerLine}")
}

